    AND month = 'DMONTH'
    AND day   = 'DDAY'
    AND hour(from_iso8601_timestamp("timestamp")) = DHOUR
)
SELECT
  h                                        AS hour,
  tag_name,
  avg(tag_val)                             AS avg_val,
  max(tag_val)                             AS max_val,
  min(tag_val)                             AS min_val,
  count(*)                                 AS samples,
  'DYEAR'                                  AS year,
  'DMONTH'                                 AS month,
  'DDAY'                                   AS day
FROM src
CROSS JOIN UNNEST(tag_names, tag_vals) AS t(tag_name, tag_val)
WHERE tag_val IS NOT NULL
GROUP BY h, tag_name
;
